refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image = imresize(image, [240 320]);
reference = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
reference = imresize(reference, [240 320]);
out = imhistmatch(image, reference, 256);
subplot(1, 3, 1);
imshow(image);
subplot(1, 3, 2);
imshow(reference);
subplot(1, 3, 3);
imshow(out);
